(() => {
    type Shape =
      | {kind: 'circle'; radius: number}
      | {kind: 'square'; x: number}
      | {kind: 'triangle'; base: number; height: number};
    return {build: () => createValidate<Exclude<Shape, {kind: 'circle'}>>(), buildErrors: () => noErrs(createGetValidationErrors<Exclude<Shape, {kind: 'circle'}>>())};
  })()

{
    build: () => {
      type Shape =
        | {kind: 'circle'; radius: number}
        | {kind: 'square'; x: number}
        | {kind: 'triangle'; base: number; height: number};
      const check = typia.createIs<Exclude<Shape, {kind: 'circle'}>>();
      return (v) => check(v);
    },
    buildErrors: () => {
      type Shape =
        | {kind: 'circle'; radius: number}
        | {kind: 'square'; x: number}
        | {kind: 'triangle'; base: number; height: number};
      const val = typia.createValidate<Exclude<Shape, {kind: 'circle'}>>();
      return (v) => val(v).success;
    },
    samples: {invalid: [{kind: 'circle', radius: 3}, {}, null, undefined, {kind: 'square'}, {kind: 'triangle', base: 4}]},
  }

c(
    Type.Exclude(
      Type.Union([
        Type.Object({kind: Type.Literal('circle'), radius: Type.Number()}),
        Type.Object({kind: Type.Literal('square'), x: Type.Number()}),
        Type.Object({kind: Type.Literal('triangle'), base: Type.Number(), height: Type.Number()}),
      ]),
      Type.Object({kind: Type.Literal('circle'), radius: Type.Number()})
    )
  )
